import React, { useState } from "react";

function App() {

  const [hcpName, setHcpName] = useState("");
  const [interactionType, setInteractionType] = useState("");
  const [date, setDate] = useState("");
  const [topics, setTopics] = useState("");
  const [sentiment, setSentiment] = useState("");
  const [followUp, setFollowUp] = useState("");
  const [aiText, setAiText] = useState("");

  const logInteraction = () => {

    const data = {
      hcpName,
      interactionType,
      date,
      topics,
      sentiment,
      followUp
    };

    console.log("Logged Interaction:", data);
    alert("Interaction Logged! Check console.");
  };

  const askAI = async () => {

    const response = await fetch("http://127.0.0.1:8000/ai-log", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        text: aiText
      })
    });

    const data = await response.json();

    setHcpName(data.hcpName);
    setInteractionType(data.interactionType);
    setTopics(data.topics);
    setSentiment(data.sentiment);
    setFollowUp(data.followUp);
  };

  return (
    <div style={page}>

      <h1 style={title}>Log HCP Interaction</h1>

      <div style={container}>

        {/* LEFT FORM */}

        <div style={leftPanel}>

          <h3 style={sectionTitle}>Interaction Details</h3>

          <div style={grid}>

            <div>
              <label style={label}>HCP Name</label>
              <input
                style={input}
                value={hcpName}
                onChange={(e)=>setHcpName(e.target.value)}
                placeholder="Search or select HCP"
              />
            </div>

            <div>
              <label style={label}>Interaction Type</label>
              <select
                style={input}
                value={interactionType}
                onChange={(e)=>setInteractionType(e.target.value)}
              >
                <option>Meeting</option>
                <option>Call</option>
              </select>
            </div>

            <div>
              <label style={label}>Date</label>
              <input
                type="date"
                style={input}
                value={date}
                onChange={(e)=>setDate(e.target.value)}
              />
            </div>

            <div>
              <label style={label}>Time</label>
              <input
                type="time"
                style={input}
              />
            </div>

          </div>

          <label style={label}>Attendees</label>
          <input style={input} placeholder="Enter names or search" />

          <label style={label}>Topics Discussed</label>
          <textarea
            style={textarea}
            value={topics}
            onChange={(e)=>setTopics(e.target.value)}
          />

          <label style={label}>Materials Shared</label>
          <textarea style={textarea} />

          <label style={label}>Samples Distributed</label>
          <textarea style={textarea} />

          <label style={label}>Observed HCP Sentiment</label>

          <div style={radioRow}>

            <label>
              <input
                type="radio"
                value="Positive"
                name="sentiment"
                onChange={(e)=>setSentiment(e.target.value)}
              /> Positive
            </label>

            <label>
              <input
                type="radio"
                value="Neutral"
                name="sentiment"
                onChange={(e)=>setSentiment(e.target.value)}
              /> Neutral
            </label>

            <label>
              <input
                type="radio"
                value="Negative"
                name="sentiment"
                onChange={(e)=>setSentiment(e.target.value)}
              /> Negative
            </label>

          </div>

          <label style={label}>Outcomes</label>
          <textarea style={textarea} />

          <label style={label}>Follow-up Actions</label>
          <textarea
            style={textarea}
            value={followUp}
            onChange={(e)=>setFollowUp(e.target.value)}
          />

          <button style={logButton} onClick={logInteraction}>
            Log Interaction
          </button>

        </div>


        {/* AI ASSISTANT */}

        <div style={rightPanel}>

          <h3 style={sectionTitle}>AI Assistant</h3>

          <p style={{color:"#aaa"}}>
            Log interaction via chat
          </p>

          <textarea
            style={aiChat}
            value={aiText}
            onChange={(e)=>setAiText(e.target.value)}
            placeholder={`Example:
Met Dr Sharma and discussed Product X.
Doctor interested. Follow up next week.`}
          />

          <button style={aiButton} onClick={askAI}>
            Ask AI
          </button>

        </div>

      </div>

    </div>
  );
}


/* PAGE */

const page = {
  minHeight:"100vh",
  background:"#0f0f0f",
  padding:"40px",
  fontFamily:"Inter, sans-serif"
};

const title = {
  color:"white",
  marginBottom:"20px"
};

const container = {
  display:"flex",
  gap:"30px"
};

const leftPanel = {
  flex:2,
  background:"#181818",
  padding:"25px",
  borderRadius:"12px",
  color:"white"
};

const rightPanel = {
  flex:1,
  background:"#181818",
  padding:"25px",
  borderRadius:"12px",
  height:"fit-content",
  color:"white"
};

const sectionTitle = {
  marginBottom:"20px"
};

const grid = {
  display:"grid",
  gridTemplateColumns:"1fr 1fr",
  gap:"15px"
};

const label = {
  display:"block",
  marginBottom:"5px",
  color:"#aaa",
  fontSize:"14px"
};

const input = {
  width:"100%",
  padding:"10px",
  marginBottom:"15px",
  borderRadius:"6px",
  border:"1px solid #333",
  background:"#111",
  color:"white"
};

const textarea = {
  width:"100%",
  padding:"10px",
  marginBottom:"15px",
  borderRadius:"6px",
  border:"1px solid #333",
  background:"#111",
  color:"white"
};

const radioRow = {
  display:"flex",
  gap:"20px",
  marginBottom:"15px"
};

const logButton = {
  width:"100%",
  padding:"12px",
  border:"none",
  borderRadius:"8px",
  background:"linear-gradient(90deg,#ff4d6d,#ff758c)",
  color:"white",
  cursor:"pointer"
};

const aiChat = {
  width:"100%",
  height:"200px",
  padding:"10px",
  borderRadius:"8px",
  border:"1px solid #333",
  background:"#111",
  color:"white",
  marginTop:"10px"
};

const aiButton = {
  width:"100%",
  padding:"12px",
  marginTop:"10px",
  border:"none",
  borderRadius:"8px",
  background:"linear-gradient(90deg,#00c6ff,#0072ff)",
  color:"white",
  cursor:"pointer"
};

export default App;
